var admin = null;
function getAdmin() {
  if (admin) return admin;
  var a = require('firebase-admin');
  if (!a.apps.length) {
    var sa = JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT || '{}');
    a.initializeApp({ credential: a.credential.cert(sa) });
  }
  admin = a;
  return a;
}

